require('dotenv').config();
var createError = require('http-errors');
var express = require('express');
var path = require('path');
var cookieParser = require('cookie-parser');
var logger = require('morgan');
let mongoose = require('mongoose');
var cors = require('cors'); // <== Thêm thư viện CORS để Frontend gọi API không bị chặn

var app = express();

// view engine setup
app.set('views', path.join(__dirname, 'views'));
app.set('view engine', 'ejs');

// 🚀 ĐÃ CẬP NHẬT: Cấp phép cho mọi domain (Frontend) được phép gọi API kèm Token
app.use(cors({
  origin: '*', // Cho phép tất cả các trang web gọi vào
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'], // Cho phép các hành động này
  allowedHeaders: ['Content-Type', 'Authorization'] // Quan trọng nhất: Cho phép mang theo Token xác thực!
}));

app.use(logger('dev'));
app.use(express.json());
app.use(express.urlencoded({ extended: false }));
app.use(cookieParser());
app.use(express.static(path.join(__dirname, 'public')));

// Kết nối Database qua biến môi trường (MongoDB Atlas)
mongoose.connect(process.env.MONGODB_URI)
  .then(() => console.log('Đã kết nối Database thành công!'))
  .catch((err) => console.error('Lỗi kết nối DB:', err));

// KHAI BÁO CÁC ĐƯỜNG DẪN API (ROUTES)
app.use('/api/v1/', require('./routes/index'));
app.use('/api/v1/users', require('./routes/users'));
app.use('/api/v1/roles', require('./routes/roles'));
app.use('/api/v1/products', require('./routes/products'));
app.use('/api/v1/categories', require('./routes/categories'));
app.use('/api/v1/auth', require('./routes/auth'));
app.use('/api/v1/inventories', require('./routes/inventories'));
app.use('/api/v1/carts', require('./routes/carts'));
app.use('/api/v1/upload', require('./routes/upload'));
app.use('/api/v1/orders', require('./routes/orders')); 
app.use('/api/v1/reviews', require('./routes/reviews')); 
app.use('/api/v1/vouchers', require('./routes/vouchers')); 
app.use('/api/v1/chats', require('./routes/chats')); // 🚀 <== ĐÃ MỞ CỔNG CHO TRUNG TÂM NHẮN TIN (CHATS)
app.use('/api/v1/reservations', require('./routes/reservations')); // 🚀 <== CỔNG MỚI CHO GIỮ HÀNG

// catch 404 and forward to error handler
app.use(function (req, res, next) {
  next(createError(404));
});

// error handler
app.use(function (err, req, res, next) {
  // set locals, only providing error in development
  res.locals.message = err.message;
  res.locals.error = req.app.get('env') === 'development' ? err : {};

  // render the error page
  res.status(err.status || 500);
  res.send(err.message);
});

module.exports = app;

let modelProduct = require('../schemas/products');
let modelInventory = require('../schemas/inventories');
const { default: mongoose } = require('mongoose');
let slugify = require('slugify');

module.exports = {
    // [GET] Lấy danh sách sản phẩm (có lọc và phân trang của thầy)
    getAllProducts: async function (req, res, next) {
        let data = await modelProduct.find({});
        let queries = req.query;
        let titleQ = queries.title ? queries.title.toLowerCase() : '';
        
        // CẬP NHẬT Ở ĐÂY NÈ NÍ: Đổi 1E4 thành 1E9 (1 tỷ) để không bị mất sản phẩm giá cao
        let maxPrice = queries.maxPrice ? queries.maxPrice : 1E9; 
        
        let minPrice = queries.minPrice ? queries.minPrice : 0;
        let limit = queries.limit ? parseInt(queries.limit) : 5;
        let page = queries.page ? parseInt(queries.page) : 1;
        
        let result = data.filter(function (e) {
            return (!e.isDeleted) && 
                   e.price >= minPrice && 
                   e.price <= maxPrice && 
                   e.title.toLowerCase().includes(titleQ);
        });
        
        result = result.splice(limit * (page - 1), limit);
        res.send(result);
    },

    // [GET] Lấy chi tiết 1 sản phẩm
    getProductById: async function (req, res, next) {
        try {
            let id = req.params.id;
            let result = await modelProduct.findById(id);
            if (result && (!result.isDeleted)) {
                res.send(result);
            } else {
                res.status(404).send({ message: "ID not found" });
            }
        } catch (error) {
            res.status(404).send({ message: "ID not found" });
        }
    },

    // [POST] Thêm mới sản phẩm (Dùng Transaction)
    createProduct: async function (req, res, next) {
        let session = await mongoose.startSession();
        session.startTransaction();
        try {
            let newObj = new modelProduct({
                title: req.body.title,
                // Fix lỗi thiếu SKU (Nếu client ko gửi lên thì tự generate)
                sku: req.body.sku || "SKU-" + Date.now(), 
                slug: slugify(req.body.title, {
                    replacement: '-', remove: undefined,
                    locale: 'vi', trim: true
                }), 
                price: req.body.price,
                description: req.body.description,
                category: req.body.category,
                images: req.body.images
            });
            
            let newProduct = await newObj.save({ session });
            
            let newInv = new modelInventory({
                product: newProduct._id,
                stock: 100
            });
            await newInv.save({ session });
            
            await session.commitTransaction();
            session.endSession();
            res.send(newProduct);
        } catch (error) {
            await session.abortTransaction();
            session.endSession();
            res.status(400).send({ message: error.message });
        }
    },

    // [PUT] Cập nhật sản phẩm
    updateProduct: async function (req, res, next) {
        let id = req.params.id;
        try {
            let result = await modelProduct.findByIdAndUpdate(
                id, req.body, { new: true }
            );
            res.send(result);
        } catch (error) {
            res.status(404).send({ message: "ID not found" });
        }
    },

    // [DELETE] Xóa mềm sản phẩm
    deleteProduct: async function (req, res, next) {
        let id = req.params.id;
        try {
            let result = await modelProduct.findByIdAndUpdate(
                id, { isDeleted: true }, { new: true }
            );
            res.send(result);
        } catch (error) {
            res.status(404).send({ message: "ID not found" });
        }
    }
};

let userModel = require('../schemas/users')
