    let user = await userController.FindUserById(req.userId);
    console.log(user);
    if (bcrypt.compareSync(oldpassword, user.password)) {
        user.password = newpassword;
        await user.save();
        res.send("password da duoc thay doi")
    } else {
        res.status(404).send("old password sai")
    }

