let jwt = require('jsonwebtoken')
let userController = require('../controllers/users')
module.exports = {
    checkLogin: async function (req, res, next) {
        let token
        if (req.cookies.token) {
            token = req.cookies.token
        } else {
            token = req.headers.authorization;
            if (!token || !token.startsWith("Bearer")) {
                res.status(403).send("ban chua dang nhap")
                return;
            }
            token = token.split(' ')[1];
        }
        let result = jwt.verify(token, 'secret');
        if (result && result.exp * 1000 > Date.now()) {
            req.userId = result.id;
            next();
        } else {
            res.status(403).send("ban chua dang nhap")
        }
    },
    checkRole: function (...requiredRole) {
        return async function (req, res, next) {
            let userId = req.userId;
            let user = await userController.FindUserById(userId);
            let currentRole = user.role.name;
            if (requiredRole.includes(currentRole)) {
                next();
            } else {
                res.status(403).send({ message: "ban khong co quyen" });
            }
        }
    }
}

let multer = require('multer')
let path = require('path')

// ĐỔI CHIẾN THUẬT: KHÔNG LƯU Ổ CỨNG NỮA, LƯU TẠM VÔ RAM (MEMORY)
let storage = multer.memoryStorage(); // Vercel rất thích điều này!

let filterImage = function (req, file, cb) {
    if (file.mimetype.includes("image")) {
        cb(null, true)
    } else {
        cb(new Error("file sai dinh dang"), false)
    }
}
let filterExcel = function (req, file, cb) {
    if (file.mimetype.includes("spreadsheetml")) {
        cb(null, true)
    } else {
        cb(new Error("file sai dinh dang"), false)
    }
}
module.exports = {
    uploadImage: multer({
        storage: storage,
        limits: { fileSize: 5 * 1024 * 1024 }, // 5MB
        fileFilter: filterImage
    }),
    uploadExcel: multer({
        storage: storage,
        limits: { fileSize: 5 * 1024 * 1024 }, // 5MB
        fileFilter: filterExcel
    })
}
